// // This is a 16-bit wide 2-to-1 demultiplexer that selects between two 16-bit inputs (A and B) based on a 1-bit select signal (sel). The output (Y) should be the deselected input based on the value of sel.
module mux_2_to_1 (  
    input [15:0] A,  
    input [15:0] B,  
    input sel,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        if (sel)  
            Y = B;  
        else  
            Y = A;  
    end  
endmodule
